create.query:
mutation ConditionalDirectiveProductCreate($product: ProductCreateInput!) {
  productCreate(product: $product) {
    product {
      id
      title
      handle
      status
    }
    userErrors {
      field
      message
    }
  }
}

conditionalRead.query:
fragment ConditionalDirectiveProductBits on Product {
  aliasStatus: status
  hiddenVendor: vendor @skip(if: true)
}

query ConditionalDirectiveProductRead(
  $id: ID!
  $includeTitle: Boolean!
  $skipInline: Boolean!
  $includeSpread: Boolean!
) {
  skippedRoot: product(id: $id) @skip(if: true) {
    id
    title
  }
  includedProduct: product(id: $id) @include(if: true) {
    id
    title @include(if: $includeTitle)
    hiddenHandle: handle @include(if: false)
    ... on Product @skip(if: $skipInline) {
      productType
    }
    ...ConditionalDirectiveProductBits @include(if: $includeSpread)
  }
}

skippedCreate.query:
mutation ConditionalDirectiveSkippedProductCreate($product: ProductCreateInput!, $skipMutation: Boolean!) {
  skippedCreate: productCreate(product: $product) @include(if: true) @skip(if: $skipMutation) {
    product {
      id
      title
      handle
    }
    userErrors {
      field
      message
    }
  }
}

cleanup.query:
mutation ConditionalDirectiveProductCleanup($input: ProductDeleteInput!) {
  productDelete(input: $input) {
    deletedProductId
    userErrors {
      field
      message
    }
  }
}
